// 信号链四层 ADT 接口定义
#ifndef ADC_CHAIN_H
#define ADC_CHAIN_H

#include <stdint.h>

/* 第一层：模拟前端配置 */
typedef struct {
    uint32_t opamp_gbw_hz;      /* 运放增益带宽积 */
    uint32_t source_impedance;   /* 信号源阻抗 (Ω) */
    uint32_t sampling_cap_pf;    /* 采样电容 (pF) */
} adc_afe_config_t;

/* 第二层：参考电压配置 */
typedef struct {
    float vref_nominal;          /* 标称参考电压 */
    float vref_noise_max_uv;     /* 最大允许噪声 (μVrms) */
} adc_vref_config_t;

/* 第三层：ADC 驱动接口 */
typedef struct {
    uint16_t bits;               /* 分辨率: 10/12/16 */
    uint32_t clk_hz;             /* ADC 时钟 */
    uint32_t sample_cycles;      /* SMPR 采样周期数 */
} adc_driver_config_t;

/* 第四层：数字滤波接口 */
typedef struct {
    float ema_alpha;             /* EMA 系数: 2/(N+1) */
    float spike_limit;           /* 尖峰限幅阈值 */
} adc_filter_config_t;

/* 校准常量 - 每颗芯片不同 */
extern const float g_adc_offset_calib;  /* 偏移校准值 */
extern const float g_adc_gain_calib;    /* 增益校准值 */

#endif

#define EMA_ALPHA_SHIFT 4  /* alpha = 1/16 = 右移4位 */
#define CALIB_SAMPLES 100

static float g_ema_state = 0.0f;
static float g_adc_offset_calib = 0.0f;

/* 校准流程：进系统前执行一次 */
void adc_calibration_run(void)
{
    /* 1. 停止 ADC */
    HAL_ADC_Stop(&hadc1);

    /* 2. 芯片级自校准（消除内部偏移） */
    HAL_ADCEx_Calibration_Start(&hadc1);

    /* 3. 等待内部状态机稳定 */
    HAL_Delay(1);

    /* 4. 短路所有输入到 GND，采样求平均 */
    float sum = 0.0f;
    for (int i = 0; i < CALIB_SAMPLES; i++) {
        HAL_ADC_Start(&hadc1);
        HAL_ADC_PollForConversion(&hadc1, 10);
        uint16_t raw = (uint16_t)HAL_ADC_GetValue(&hadc1);
        sum += raw;
    }
    g_adc_offset_calib = sum / CALIB_SAMPLES;

    /* 5. 恢复正常工作 */
    HAL_ADC_Start(&hadc1);
}

/* 生产级采样：校准 + 转换 + EMA 滤波 */
float adc_sample_smoothed(void)
{
    /* 等待转换完成 */
    HAL_ADC_PollForConversion(&hadc1, 10);

    /* 读原始值 */
    uint16_t raw = (uint16_t)HAL_ADC_GetValue(&hadc1);

    /* 减去偏移校准 */
    float calibrated = (float)raw - g_adc_offset_calib;

    /* 钳位到合法范围 */
    if (calibrated < 0.0f) calibrated = 0.0f;
    if (calibrated > 4095.0f) calibrated = 4095.0f;

    /* EMA 滤波: new = alpha*raw + (1-alpha)*old */
    /* alpha=1/16 时，用移位实现：state = (raw << 4 - state) >> 4 */
    g_ema_state = ((calibrated << EMA_ALPHA_SHIFT) - g_ema_state)
                  >> EMA_ALPHA_SHIFT;

    /* 转换为电压 */
    return g_ema_state * 3.3f / 4095.0f;
}

// 陷阱四修复：自适应 EMA alpha 选择
// 根据采样率动态计算 alpha，保证时间常数 ≤ 10ms
static uint8_t calc_ema_alpha(float sample_rate_hz, float max_delay_ms)
{
    /* 时间常数 T = 1/(alpha * fs)，要求 T <= max_delay_ms */
    /* alpha >= max_delay_ms / (1000.0 / sample_rate_hz) */
    float min_alpha = max_delay_ms / (1000.0f / sample_rate_hz);

    /* alpha 必须在 (0, 1] 范围内 */
    if (min_alpha >= 1.0f) min_alpha = 0.5f;  /* 最快响应 */

    /* 取最近的 2 的负幂次：1/2, 1/4, 1/8, 1/16, 1/32, 1/64, 1/128 */
    int shift = 1;
    while ((1.0f / (1 << shift)) > min_alpha && shift < 8) {
        shift++;
    }
    return (uint8_t)shift;
}

// 使用示例：1kHz 采样率，最大延迟 10ms
// calc_ema_alpha(1000.0f, 10.0f) 返回 4 → alpha = 1/16
// calc_ema_alpha(1000.0f, 50.0f) 返回 7 → alpha = 1/128

/* ========== 重构前：main 循环中裸操作 ADC（坏味道：依恋情妇 + 过长函数）========== */
void main_loop(void)
{
    HAL_ADC_Start(&hadc1);
    HAL_ADC_PollForConversion(&hadc1, 10);
    uint16_t raw = HAL_ADC_GetValue(&hadc1);
    float voltage = raw * 3.3f / 4095.0f;  /* 裸转换，无校准 */

    /* EMA 滤波写在 main 里 */
    static float ema = 0;
    ema = 0.9375f * ema + 0.0625f * voltage;  /* magic number! */

    /* 判断阈值也写在 main 里 */
    if (voltage > 3.0f) {
        HAL_GPIO_TogglePin(GPIOD, GPIO_PIN_12);  /* LED */
    }
}

/* ========== 重构后：信号链 ADT 封装 ========== */
/* adc_chain.h */
typedef struct {
    uint16_t resolution_bits;    /* 10/12/16 */
    float vref_mv;               /* 参考电压 mV */
    float ema_alpha;             /* 滤波系数 0<α≤1 */
    float offset_calib;          /* 偏移校准值 */
    uint32_t sample_period;      /* SMPR 采样周期 */
} adc_chain_config_t;

extern float adc_chain_sample(adc_chain_config_t *cfg);
extern void adc_chain_calibrate(adc_chain_config_t *cfg);
extern void adc_chain_init(ADC_HandleTypeDef *hadc, adc_chain_config_t *cfg);

/* adc_chain.c */
static float g_ema_state = 0.0f;

void adc_chain_init(ADC_HandleTypeDef *hadc, adc_chain_config_t *cfg)
{
    cfg->offset_calib = 0.0f;
    cfg->vref_mv = 3300.0f;
    cfg->ema_alpha = 0.0625f;  /* 1/16 */
    cfg->sample_period = 239;
    g_ema_state = 0.0f;
}

float adc_chain_sample(adc_chain_config_t *cfg)
{
    HAL_ADC_PollForConversion(&hadc1, 10);
    uint16_t raw = (uint16_t)HAL_ADC_GetValue(&hadc1);

    /* 校准：减去偏移 */
    float calibrated = (float)raw - cfg->offset_calib;
    if (calibrated < 0) calibrated = 0;
    if (calibrated > 65535) calibrated = 65535;

    /* 转换为电压 (mV) */
    float mv = calibrated * cfg->vref_mv / (float)((1 << cfg->resolution_bits) - 1);

    /* EMA 滤波 */
    g_ema_state = cfg->ema_alpha * mv + (1.0f - cfg->ema_alpha) * g_ema_state;

    return g_ema_state;
}

void adc_chain_calibrate(ADC_HandleTypeDef *hadc, adc_chain_config_t *cfg)
{
    HAL_ADC_Stop(hadc);
    HAL_ADCEx_Calibration_Start(hadc);
    HAL_Delay(1);

    float sum = 0.0f;
    for (int i = 0; i < 100; i++) {
        HAL_ADC_Start(hadc);
        HAL_ADC_PollForConversion(hadc, 10);
        sum += (float)(uint16_t)HAL_ADC_GetValue(hadc);
    }
    cfg->offset_calib = sum / 100.0f;
    HAL_ADC_Start(hadc);
}

/* 重构后 main 循环：干净利落 */
void main_loop(void)
{
    adc_chain_config_t cfg;
    adc_chain_init(&hadc1, &cfg);
    adc_chain_calibrate(&hadc1, &cfg);

    for (;;) {
        float voltage_mv = adc_chain_sample(&cfg);
        if (voltage_mv > 3000.0f) {
            HAL_GPIO_TogglePin(GPIOD, GPIO_PIN_12);
        }
    }
}
